const raw = items[0].json.text || '';
const cleaned = raw.replace(/```json/gi,'').replace(/```/g,'').trim();

let p = {};
try { p = JSON.parse(cleaned); } catch(e) {
  p = {};
}

const clamp = (v, min, max) => Math.min(Math.max(parseFloat(v) || min, min), max);

return [{ json: {
  response_language: (p.response_language || 'es').toLowerCase().slice(0,5),
  query:             (p.query          || '').slice(0, 100).replace(/[<>{}[\]]/g,''),
  genre:             (p.genre          || '').slice(0,  50).replace(/[^a-zA-Z ,]/g,''),
  language:          (p.language       || '').slice(0,   5).replace(/[^a-z]/g,''),
  country:           (p.country        || '').slice(0,  60).replace(/[<>{}[\]]/g,''),
  min_rating:        clamp(p.min_rating,     0, 10),
  max_rating:        clamp(p.max_rating !== undefined ? p.max_rating : 10, 0, 10),
  min_popularity:    clamp(p.min_popularity, 0, 999999),
  max_popularity:    clamp(p.max_popularity !== undefined ? p.max_popularity : 999999, 0, 999999),
  min_votes:         clamp(p.min_votes,      0, 999999),
  year:              (p.year || '').slice(0, 9).replace(/[^0-9\-]/g,''),
  sort_mode:         ['best','worst','popular','random',''].includes(p.sort_mode) ? p.sort_mode : '',
  limit:             Math.min(Math.max(parseInt(p.limit) || 5, 1), 10)
}}];

// ── Recuperar idioma de respuesta desde el nodo Parsear JSON ─────
const responseLang = $('Parsear JSON').first().json.response_language || 'es';
const sortMode     = $('Parsear JSON').first().json.sort_mode || '';
const limit        = $('Parsear JSON').first().json.limit || 5;

if (items[0]?.json?.noResults) {
  return [{ json: { movieData: [], noResults: true, response_language: responseLang } }];
}

// ── Construir array limpio con SOLO datos del CSV ─────────────────
// NUNCA modificar ni inferir datos — se pasan tal cual del CSV
const movies = items.map(i => {
  const m = i.json;
  return {
    title:        m.title        || '',
    release_year: m.release_year || '',
    genres:       m.genres       || '',
    language:     m.language     || '',
    country:      m.country      || '',
    director:     m.director     || '',
    cast:         m.cast         || '',
    description:  m.description  || '',
    vote_average: m.vote_average || '0.0',   // String exacto del CSV, ya formateado
    vote_count:   m.vote_count   || 0,
    popularity:   m.popularity   || '0.0'
  };
});

return [{ json: {
  movieData:         movies,
  noResults:         false,
  response_language: responseLang,
  sort_mode:         sortMode,
  limit:             limit
}}];

// Última capa de seguridad: limpiar cualquier fuga de datos técnicos
let text = items[0].json.text || '';

// Eliminar posibles bloques de código o JSON en la respuesta
text = text.replace(/```[\s\S]*?```/g, '').trim();

// Eliminar patrones de inyección en el output (por si el modelo fue manipulado)
const dangerousOutputPatterns = [
  /\[INST\]/gi,
  /<\|.*?\|>/gi,
  /ignore (all|previous) instructions/gi,
  /system prompt/gi
];
for (const p of dangerousOutputPatterns) {
  text = text.replace(p, '');
}

// Limitar longitud de salida
if (text.length > 3000) {
  text = text.slice(0, 3000) + '...';
}

return [{ json: { output: text.trim() } }];

// El AI Agent escribe en .output (no .text como chainLlm)
const raw = items[0].json.output || items[0].json.text || '';
const cleaned = raw.replace(/```json/gi,'').replace(/```/g,'').trim();

let p = {};
try { p = JSON.parse(cleaned); } catch(e) { p = { related: true, blocked: false, reason: '' }; }

// Si el LLM detectó intento de manipulación
if (p.blocked === true) {
  return [{ json: { blocked: true, reason: p.reason || '🎬 Solo puedo ayudarte a encontrar películas. ¿Qué querés ver hoy?' } }];
}

// Si no es de películas
if (p.related === false) {
  return [{ json: { blocked: true, reason: p.reason || '🎬 Solo puedo recomendarte películas. ¿Querés buscar por género, actor o estado de ánimo?' } }];
}

// Es de películas — recuperar chatInput del Chat Trigger
const chatInput = $('Chat Trigger').first().json.chatInput || '';
return [{ json: { blocked: false, chatInput: chatInput } }];
